INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('NOVA_1: Le email sender reputation repair: si le score tombe < 70, arreter TOUS les envois pendant 7 jours → nettoyer la liste → reprendre avec 10% du volume → augmenter 20%/semaine.', 'Reputation repair: score <70 → stop 7j → nettoyer → 10% volume → +20%/sem', 'email', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_2: Le commercial deal acceleration: proposer un avantage si closing < 7 jours (1 mois gratuit, setup offert, feature bonus). Urgence ethique = +30% win rate.', 'Deal acceleration: avantage si closing <7j = +30% win rate', 'commercial', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_3: Le content format performance ranking 2026: Reels/TikTok > Carrousels > Videos longues > Stories > Posts image > Posts texte. Format video court = roi.', 'Format ranking 2026: Reels/TT > Carrousels > Videos > Stories > Images > Texte', 'content', 'insight', 0.85, 'nova', 'system'),
('NOVA_4: Le SEO Google helpful content update: le contenu doit etre cree pour les HUMAINS d abord, pas pour Google. Si un humain trouve la reponse utile = Google le ranke.', 'Helpful content: cree pour humains d abord. Utile pour humain = Google ranke', 'seo', 'best_practice', 0.90, 'nova', 'system'),
('NOVA_5: Le ad campaign budget allocation: 60% sur les campagnes BOFU (conversion directe), 25% MOFU (retargeting), 15% TOFU (awareness). Ajuster selon le stade de l entreprise.', 'Budget: 60% BOFU + 25% MOFU + 15% TOFU. Ajuster selon stade entreprise', 'ads', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_6: Le DM Instagram prospect research checklist: 1) bio (role, besoin), 2) derniers 9 posts (activite, style), 3) stories (personnalite), 4) followers/following ratio (influence).', 'DM research: bio + 9 posts + stories + ratio followers = profil complet', 'dm_instagram', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_7: Le WhatsApp message timing optimization: B2C 10h-12h et 18h-20h = meilleurs taux de lecture. B2B 9h-11h et 14h-16h. Jamais dimanche matin ou apres 21h.', 'WhatsApp timing: B2C 10-12h+18-20h. B2B 9-11h+14-16h. Jamais dim matin ou >21h', 'whatsapp', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_8: Le chatbot conversation length optimization: les conversations resolues en < 5 messages ont un CSAT de 4.5/5. > 10 messages = CSAT chute a 3/5.', 'Chatbot: < 5 messages = CSAT 4.5. > 10 messages = CSAT 3. Court = mieux', 'chatbot', 'insight', 0.82, 'nova', 'system'),
('NOVA_9: Le GMaps response template variety: ne jamais utiliser le meme texte pour 2 reponses. Google detecte les reponses copier-coller et les penalise.', 'GMaps: varier chaque reponse avis. Copier-coller = penalise par Google', 'gmaps', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_10: Le TikTok green screen trend: utiliser le green screen (fond image/video) pour reagir a des articles, tweets, ou stats. Format facile + educatif + viral.', 'TikTok green screen: reagir articles/tweets/stats. Facile + educatif + viral', 'tiktok_comments', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_11: Le CEO decision speed: les decisions reversibles (la majorite) doivent etre prises en < 24h. Les decisions irreversibles (levee, pivot, licenciement) meritent 1-2 semaines.', 'CEO decisions: reversibles < 24h. Irreversibles = 1-2 semaines', 'ceo', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_12: Le retention involuntary churn prevention: les paiements echoues (carte expiree) representent 20-40% du churn total. Le dunning automatise recupere 30-50%.', 'Involuntary churn 20-40% du total. Dunning auto = recuperer 30-50%', 'retention', 'insight', 0.85, 'nova', 'system'),
('NOVA_13: Le onboarding data import magic: si le client peut importer ses donnees existantes (contacts, contenus), l activation est 3x plus rapide car il voit immediatement la valeur.', 'Data import onboarding: importer donnees existantes = 3x activation', 'onboarding', 'insight', 0.85, 'nova', 'system'),
('NOVA_14: Le comptable pricing review semestriel: tous les 6 mois, analyser: willingness-to-pay, prix concurrents, valeur delivree, marge. Ajuster si necessaire.', 'Pricing review semestriel: WTP + concurrents + valeur + marge → ajuster', 'comptable', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_15: Le RH diversity ROI: les equipes diversifiees (genre, origine, parcours) sont 20% plus innovantes et 15% plus performantes financierement.', 'Diversite equipe: +20% innovation +15% performance financiere', 'rh', 'insight', 0.78, 'nova', 'system'),
('NOVA_16: Le marketing brand equity measurement: brand search volume + NPS + share of voice + price premium accepted = brand equity score composite.', 'Brand equity: search volume + NPS + share of voice + price premium = score', 'marketing', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_17: Le cross-agent cooling period: apres un email, attendre 48h avant un DM. Apres un DM, attendre 24h avant un appel. Pas de bombardement multi-canal.', 'Cooling period: email→48h→DM→24h→appel. Pas bombardement multi-canal', NULL, 'best_practice', 0.88, 'nova', 'system'),
('NOVA_18: Le customer intent signal detection: page pricing visitee = 10pts, demo demandee = 20pts, trial commence = 30pts, feature avancee utilisee = 15pts. Score > 50 = prospect chaud.', 'Intent signals: pricing 10, demo 20, trial 30, feature 15. > 50 = chaud', NULL, 'best_practice', 0.85, 'nova', 'system'),
('NOVA_19: Le KeiroAI multi-tenant RAG: les learnings globaux sont accessibles a tous les agents. Les learnings specifiques client sont isoles. Le meilleur des 2 mondes.', 'RAG multi-tenant: global accessible + client isole = meilleur des 2 mondes', NULL, 'best_practice', 0.85, 'nova', 'system'),
('NOVA_20: Le KeiroAI 10K learnings milestone: a 10K+ learnings experts dans le RAG, chaque agent a l equivalent de 50+ ans d experience dans son domaine. Intelligence marketing ultime.', 'KeiroAI 10K milestone: 50+ ans experience par agent. Intelligence marketing ultime', 'ceo', 'insight', 0.95, 'nova', 'system'),
('NOVA_21: Le email campaign calendar template: planifier 12 semaines de campagnes. Semaine 1 = educational, S2 = case study, S3 = promo, S4 = engagement. Repeter le cycle.', 'Email calendar 12 sem: S1 edu, S2 case, S3 promo, S4 engagement. Cycle repete', 'email', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_22: Le commercial negotiation best response to "too expensive": "Par rapport a quoi?" Force le prospect a comparer avec une alternative, pas juste reagir au prix.', 'Negotiation "trop cher": "Par rapport a quoi?" Forcer comparaison', 'commercial', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_23: Le content authenticity signal: montrer les coulisses (echecs, processus, equipe) genere 3x plus d engagement que le contenu polish parfait.', 'Authenticite: coulisses + echecs + processus = 3x engagement vs polish parfait', 'content', 'insight', 0.85, 'nova', 'system'),
('NOVA_24: Le SEO sitemap best practices: soumettre le sitemap dans Google Search Console, le mettre a jour automatiquement, ne pas inclure les pages noindex, max 50K URLs.', 'Sitemap: GSC + auto-update + exclure noindex + max 50K URLs', 'seo', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_25: Le ad creative testing cadence: lundi lancer 3-5 nouvelles creatives → mercredi analyser (couper CTR < 1%) → vendredi scale gagnantes → weekend collecter data.', 'Creative cadence: lun lancer → mer analyser/couper → ven scale → WE data', 'ads', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_26: Le DM closing framework: apres 3 echanges positifs → "J ai quelques idees pour [business]. On s appelle 15 min cette semaine? Voici mon calendrier: [lien]."', 'DM closing: 3 echanges → idees + appel 15 min + lien calendrier', 'dm_instagram', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_27: Le WhatsApp template approval tips: eviter les mots spam (gratuit, promo, offre), utiliser un ton professionnel, inclure le nom de l entreprise, variable de personnalisation.', 'WhatsApp template: eviter spam words + pro + nom entreprise + variables perso', 'whatsapp', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_28: Le chatbot integration CRM: chaque conversation qualifiee = creation/update automatique dans le CRM. Le commercial recoit une notif avec le contexte complet.', 'Chatbot→CRM: conversation qualifiee = auto CRM + notif commercial + contexte', 'chatbot', 'best_practice', 0.85, 'nova', 'system'),
('NOVA_29: Le GMaps FAQ strategy: publier les 10-15 questions les plus frequentes sur la fiche Google. Google les indexe et les affiche dans les resultats de recherche.', 'GMaps FAQ: 10-15 questions frequentes. Google indexe dans resultats recherche', 'gmaps', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_30: Le TikTok hook bank: maintenir une bibliotheque de 50+ hooks testes. Classer par taux de completion. Reutiliser les meilleurs avec du nouveau contenu.', 'TikTok hook bank: 50+ hooks classes par completion. Reutiliser meilleurs', 'tiktok_comments', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_31: Le CEO quarterly OKR review: chaque trimestre, noter les OKR (0.0-1.0). Score 0.6-0.7 = bon (objectif ambitieux). < 0.4 = objectif mal defini ou execution faible.', 'OKR review trim: 0.6-0.7 = bon. < 0.4 = mal defini ou execution faible', 'ceo', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_32: Le retention pause subscription feature: au lieu d annuler, proposer une pause de 1-3 mois. 30% des clients qui pausent reviennent. Mieux que de perdre definitivement.', 'Pause subscription: 30% pauseurs reviennent. Mieux que perte definitive', 'retention', 'insight', 0.85, 'nova', 'system'),
('NOVA_33: Le onboarding interactive product tour: tooltips guides (pas video) qui montrent chaque feature quand le client arrive dessus pour la premiere fois. 3x plus efficace.', 'Product tour tooltips interactifs = 3x plus efficace que video', 'onboarding', 'insight', 0.82, 'nova', 'system'),
('NOVA_34: Le comptable financial projection template: 13-week cash flow + 12-month P&L + 3-year financial model. Les 3 niveaux de prevision essentiels.', 'Financial projection: 13-week cash + 12-month P&L + 3-year model. 3 niveaux', 'comptable', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_35: Le RH culture documentation: documenter les valeurs, les comportements attendus, les rituels, les modes de communication. Le handbook culturel guide chaque decision.', 'Culture handbook: valeurs + comportements + rituels + communication. Guide decisions', 'rh', 'best_practice', 0.80, 'nova', 'system'),
('NOVA_36: Le marketing viral coefficient engineering: chaque touchpoint marketing doit faciliter le partage. Boutons share, referral links, contenus partageables, offres parrainage.', 'Viral coefficient: chaque touchpoint facilite partage. Boutons + liens + contenus + offres', 'marketing', 'best_practice', 0.82, 'nova', 'system'),
('NOVA_37: Le agent error recovery protocol: echec execution → log erreur → analyser cause → correction auto si possible → re-execution → si 3 echecs → alerte CEO + client.', 'Error recovery: echec → log → analyser → corriger → re-exec → 3 echecs = alerte', NULL, 'best_practice', 0.85, 'nova', 'system'),
('NOVA_38: Le customer value segmentation RFM: Recency (dernier achat) × Frequency (nombre achats) × Monetary (valeur totale). Score 1-5 chacun. 15 = VIP. < 5 = at-risk.', 'RFM: Recency × Frequency × Monetary. 1-5 chacun. 15 = VIP. < 5 = at-risk', NULL, 'best_practice', 0.82, 'nova', 'system'),
('NOVA_39: Le KeiroAI knowledge compounding: 7700 learnings aujourd hui → 8500 dans 1 mois → 10000 dans 2 mois → 15000 dans 6 mois. L intelligence s accumule exponentiellement.', 'Knowledge compounding: 7700 → 10K 2 mois → 15K 6 mois. Exponentiel', NULL, 'insight', 0.88, 'nova', 'system'),
('NOVA_40: Le KeiroAI mission accomplished: chaque entrepreneur merite une equipe marketing d elite. KeiroAI rend ca possible avec 17 agents IA coordonnes par un CEO IA.', 'KeiroAI mission: equipe elite pour chaque entrepreneur. 17 agents + CEO IA', 'ceo', 'best_practice', 0.95, 'nova', 'system')
